import org.apache.kafka.clients.producer.*;
import java.util.*;
import java.util.concurrent.*;

public class HotPartitionDemo {
    static final String TOPIC   = "events";
    static final String SERVERS = "localhost:9092";
    static final int    TOTAL   = 1000;
    static final int    SPLITS  = 4;

    public static void main(String[] args) throws Exception {
        Properties props = new Properties();
        props.put("bootstrap.servers", SERVERS);
        props.put("key.serializer",
            "org.apache.kafka.common.serialization.StringSerializer");
        props.put("value.serializer",
            "org.apache.kafka.common.serialization.StringSerializer");

        KafkaProducer<String, String> producer = new KafkaProducer<>(props);

        // TODO 1: Single key — splits=1 means the key is always "vip_user-0" (one key only)
        System.out.println("=== Hot partition scenario: single key 'vip_user' ===");
        Map<Integer, Integer> hotResult = sendAndCount(producer, "vip_user", TOTAL, 1);
        printDistribution(hotResult, TOTAL);

        // TODO 2: Composite key — splits=4 distributes across 'vip_user-0' through 'vip_user-3'
        System.out.println("\n=== Skew resolved: composite key 'vip_user-{0~3}' ===");
        Map<Integer, Integer> fixedResult = sendAndCount(producer, "vip_user", TOTAL, SPLITS);
        printDistribution(fixedResult, TOTAL);

        producer.close();
    }

    static Map<Integer, Integer> sendAndCount(
            KafkaProducer<String, String> producer,
            String keyPrefix, int total, int splits) throws Exception {
        Map<Integer, Integer> counts = new TreeMap<>();
        List<Future<RecordMetadata>> futures = new ArrayList<>();

        for (int i = 0; i < total; i++) {
            // splits=1: fixed key; splits>1: round-robin across buckets
            String key   = splits == 1 ? keyPrefix : keyPrefix + "-" + (i % splits);
            String value = "event-" + i;
            futures.add(producer.send(new ProducerRecord<>(TOPIC, key, value)));
        }
        producer.flush(); // flush async batch immediately

        for (Future<RecordMetadata> f : futures) {
            int partition = f.get().partition();
            counts.merge(partition, 1, Integer::sum);
        }
        return counts;
    }

    static void printDistribution(Map<Integer, Integer> counts, int total) {
        counts.forEach((partition, count) -> {
            double pct = count * 100.0 / total;
            String bar = "#".repeat((int)(pct / 2)); // scale to 50 chars
            System.out.printf("partition %d: %4d msgs (%5.1f%%) %s%n",
                partition, count, pct, bar);
        });
    }
}

/* Expected output example:
   === Hot partition scenario: single key 'vip_user' ===
   partition 1: 1000 msgs (100.0%) ##################################################

   === Skew resolved: composite key 'vip_user-{0~3}' ===
   partition 0:  252 msgs ( 25.2%) ############
   partition 1:  251 msgs ( 25.1%) ############
   partition 2:  249 msgs ( 24.9%) ############
   partition 3:  248 msgs ( 24.8%) ############
   (actual partition numbers and percentages may vary depending on hash values)
*/

